import { Vex } from 'vex-sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

async function generateContent(query: string, seoKeywords: string[]): Promise<string> {
  const response = await queryEngine.query(query + ` SEO: ${seoKeywords.join(', ')}`);

  const verified = await vex.verify({
    input: response.response,
    checks: [
      'brand_consistency:voice=professional_approachable',
      'factual_accuracy:against_sources',
      'tone_adherence:score>0.9',
      'seo_compliance:keywords_present',
    ],
    riskProfile: 'medium'
  });

  return verified.output || response.response;
}
